const e=JSON.parse('{"key":"v-6951d75e","path":"/learningNote/Computer_Network/%E5%85%B3%E4%BA%8EVLAN.html","title":"VLAN","lang":"zh-CN","frontmatter":{"title":"VLAN","category":["Computer","Network","basic"]},"headers":[{"level":2,"title":"五、关于VLAN（3.1-3.3）","slug":"五、关于vlan-3-1-3-3","link":"#五、关于vlan-3-1-3-3","children":[{"level":3,"title":"1、概念（3.1）","slug":"_1、概念-3-1","link":"#_1、概念-3-1","children":[]},{"level":3,"title":"2、VLAN标签（重要）（3.1）","slug":"_2、vlan标签-重要-3-1","link":"#_2、vlan标签-重要-3-1","children":[]},{"level":3,"title":"3、VLAN标签的结构（重要）（3.1）","slug":"_3、vlan标签的结构-重要-3-1","link":"#_3、vlan标签的结构-重要-3-1","children":[]},{"level":3,"title":"4、以太网链路与VLAN端口（3.2-3.3）","slug":"_4、以太网链路与vlan端口-3-2-3-3","link":"#_4、以太网链路与vlan端口-3-2-3-3","children":[]}]}],"git":{"createdTime":1692780329000,"updatedTime":1692780329000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":9.04,"words":2712},"filePathRelative":"learningNote/Computer_Network/关于VLAN.md","localizedDate":"2023年8月23日","excerpt":"<h2> 五、关于VLAN（3.1-3.3）</h2>\\n<h3> 1、概念（3.1）</h3>\\n<p>VLAN（Virtual Local Area Network）即虚拟局域网，是将一个物理的LAN（局域网）在逻辑上划分成多个广播域的通信技术。VLAN内的主机间可以直接通信，而VLAN间不能直接通信，从而将广播报文限制在一个VLAN内。</p>\\n<p>换句话说，即使是不同交换机下所属的设备，只要存在于同一个VLAN中，也可以实现在进行设备间通信的同时不产生除有效流量外的垃圾流量的效果。可以优化网络性能，区分相关业务，以及拥有安全性。</p>\\n<p></p>\\n<h3> 2、VLAN标签（重要）（3.1）</h3>"}');export{e as data};
